QueryExtension.Constraint:
	( (     CP.ADMIN_COURT_CODE = 0
        OR (CP.ADMIN_COURT_CODE = 335 
            AND CP.CODE BETWEEN 1500 AND 1999)
		OR (CP.ADMIN_COURT_CODE = 335 
            AND CP.CODE BETWEEN 7000 AND 9999)
	  ) AND (
		${param.code} IS NULL OR CP.CODE LIKE UPPER(${param.code}) 
	  ) AND (
			${param.partyName} IS NULL OR P.PERSON_REQUESTED_NAME LIKE UPPER(${param.partyName})
	  ) AND (
			${param.address1} IS NULL OR GA.ADDRESS_LINE1 LIKE UPPER(${param.address1})
	  ) AND (
			${param.address2} IS NULL OR GA.ADDRESS_LINE2 LIKE UPPER(${param.address2})
	  ) AND (
			${param.postCode} IS NULL OR GA.POSTCODE LIKE UPPER(${param.postCode}) 
	  )									
	)
